<?php
namespace App\Services;use App\Models\{DailyReport,DailyReportItem,PerformanceScore,Task,Team,User,Workspace,WorkProof,TaskApproval};use Carbon\Carbon;
class PerformanceScoreService{public function calculateDailyScore(Workspace $w,User $u,Carbon $d):PerformanceScore{$assigned=Task::withoutWorkspaceScope()->where('workspace_id',$w->id)->whereHas('assignees',fn($q)=>$q->where('user_id',$u->id))->count();$completed=Task::withoutWorkspaceScope()->where('workspace_id',$w->id)->where('completed_by',$u->id)->whereDate('completed_at',$d)->count();$overdue=Task::withoutWorkspaceScope()->where('workspace_id',$w->id)->whereDate('due_date','<',$d)->where('status','!=','completed')->whereHas('assignees',fn($q)=>$q->where('user_id',$u->id))->count();$reopened=Task::withoutWorkspaceScope()->where('workspace_id',$w->id)->where('status','reopened')->whereHas('assignees',fn($q)=>$q->where('user_id',$u->id))->count();$report=DailyReport::withoutWorkspaceScope()->where('workspace_id',$w->id)->where('user_id',$u->id)->whereDate('report_date',$d)->first();$blockers=DailyReportItem::withoutWorkspaceScope()->where('workspace_id',$w->id)->whereDate('created_at',$d)->where('item_type','blocker')->count();$proofRej=WorkProof::withoutWorkspaceScope()->where('workspace_id',$w->id)->where('submitted_by',$u->id)->where('status','rejected')->whereDate('reviewed_at',$d)->count();$approvalRej=TaskApproval::withoutWorkspaceScope()->where('workspace_id',$w->id)->where('requested_by',$u->id)->where('status','rejected')->whereDate('reviewed_at',$d)->count();$score=max(0,min(100,70+($completed*5)-($overdue*8)-($reopened*5)-($blockers*3)-($proofRej*5)-($approvalRej*5)+($report?10:0)-($report?->is_late?5:0)));return PerformanceScore::withoutWorkspaceScope()->updateOrCreate(['workspace_id'=>$w->id,'user_id'=>$u->id,'score_date'=>$d->toDateString(),'period_type'=>'daily'],['assigned_tasks_count'=>$assigned,'completed_tasks_count'=>$completed,'overdue_tasks_count'=>$overdue,'reopened_tasks_count'=>$reopened,'daily_report_submitted'=>(bool)$report,'daily_report_late'=>(bool)$report?->is_late,'blocker_count'=>$blockers,'proof_rejection_count'=>$proofRej,'approval_rejection_count'=>$approvalRej,'score'=>$score,'calculated_at'=>now()]);}public function calculateWeeklyScore(Workspace $w,User $u,Carbon $weekStart):PerformanceScore{$daily=collect(range(0,6))->map(fn($i)=>$this->calculateDailyScore($w,$u,$weekStart->copy()->addDays($i)));return PerformanceScore::withoutWorkspaceScope()->updateOrCreate(['workspace_id'=>$w->id,'user_id'=>$u->id,'score_date'=>$weekStart->toDateString(),'period_type'=>'weekly'],['score'=>round($daily->avg('score'),2),'assigned_tasks_count'=>$daily->sum('assigned_tasks_count'),'completed_tasks_count'=>$daily->sum('completed_tasks_count'),'overdue_tasks_count'=>$daily->sum('overdue_tasks_count'),'reopened_tasks_count'=>$daily->sum('reopened_tasks_count'),'blocker_count'=>$daily->sum('blocker_count'),'proof_rejection_count'=>$daily->sum('proof_rejection_count'),'approval_rejection_count'=>$daily->sum('approval_rejection_count'),'calculated_at'=>now()]);}public function calculateTeamScore(Workspace $w,Team $team,array $f):array{$tasks=Task::withoutWorkspaceScope()->where('workspace_id',$w->id)->where('team_id',$team->id);return ['team'=>$team,'assigned_tasks'=>$tasks->count(),'completed_tasks'=>(clone $tasks)->where('status','completed')->count(),'overdue_tasks'=>(clone $tasks)->whereDate('due_date','<',today())->where('status','!=','completed')->count()];}}
